export const simpleToolbarPartial = (showImageAnnotation = false) =>
  `
        <div class="toolbar righticon">
            <div id="toolbarContainer">
                <div id="toolbarViewer" class="toolbarHorizontalGroup">
                    <div id="toolbarViewerRight" class="toolbarHorizontalGroup">
                        <div id="editorModeSeparator" class="verticalToolbarSeparator"></div>

                        <div class="toolbarHorizontalGroup hiddenMediumView">` +
  // <button id="editButton" class="toolbarButton editbutton editButtonEventClass" type="button" tabindex="0" data-l10n-id="pdfjs-edit-button">
  //     <span data-l10n-id="pdfjs-edit-button-label"></span>
  // </button>
  `                     ${showImageAnnotation ? `
                            <button id="annotate-toggle" class="toolbarButton" type="button" tabindex="0">
                                <span>Annotate</span>
                            </button>
                        ` : ''}
                            <button id="downloadButton" class="toolbarButton downloadButtonClass downloadButtonEventClass" type="button" tabindex="0" data-l10n-id="pdfjs-save-button">
                                <span data-l10n-id="pdfjs-save-button-label"></span>
                            </button>
                        </div>

                    </div>
                </div>
            </div>
        </div>
`;