import { simpleToolbarPartial } from "./simple-toolbar.js";

export const renderTextImagePartial = () => `
<div class="row">
    <div id="imageContainer" class="col-12 viewerContainers" style="display: none;">
        ${simpleToolbarPartial(true)}
        <img id="imageViewer" style="width: 100%;height: inherit" />
    </div>
    <div id="textContainer" class="col-12 viewerContainers"  style="display: none;position:relative;">
      ${simpleToolbarPartial()}
        <p id="textViewer" style="padding:5px;width: 100%;height: inherit" ></p>
    </div>
</div>
`;
