import { simpleToolbarPartial } from "./simple-toolbar.js";

export const renderExcelPartial = () => `
        <div id="excelSheetViewer" class="viewerContainers" style="display: none;">
            ${simpleToolbarPartial()}
            <div id="sheetTabs" style="display:flex; gap:2px; justify-content:left; margin-bottom:12px;"></div>
            <div id="sheetContainer"></div>
        </div>
    `;
