import { renderPDFPartial } from './pdf.js';
import { renderDocxPartial } from './docx.js';
import { renderMediaPartial } from './media.js';
import { renderTextImagePartial } from './text-image.js';
import { renderExcelPartial } from './excel.js';
import { renderExcelViewerPartial } from './excel-viewer.js';
import { renderDownloadFilePartial } from './download.js';
import { renderPptxPartial } from './pptx.js';
import { renderViewJudgementModal } from './_view-judgement';
import { renderPassJudgementModal } from './_pass-judgement';
import { renderShareCommentModal } from './_share-comment';

export const renderMainTemplate = () => `
<div class="container-fluid" id="pdfNoPrintContainer">
  <div class="row">
    <div class="col-12">
      <div class="c-boxContainer d1">
        <div class="c-boxContainer__content">
          <div class="c-boxContainer__content--leftsection">
            <div class="doctypewrap">
              <div class="docnamewrap">
                <a id="back-button" href="javascript:;" class="backbt hidden"><i class="fas fa-arrow-left"></i></a>
                <div class="hw d1 bluecolor">
                  <h2 id="viewer-heading" class="hw__title"></h2>
                  <h3 id="viewer-sub-heading" class="hw__subtitle"></h3>
                </div>
              </div>
              <div class="iconsection">
                <a data-bs-toggle="tooltip" data-bs-placement="top" data-bs-title="Tooltip on top" class="icon editbutton editButtonEventClass"><i class="fas fa-pen"></i></a>
                <a data-bs-toggle="tooltip" data-bs-placement="top" data-bs-title="Tooltip on top" class="icon"><i class="fas fa-envelope"></i></a>
                <a href="javascript:;" data-bs-toggle="tooltip" data-bs-placement="top" data-bs-title="Pass Judgement" class="icon js-pass-judgement d-none"><i class="fas fa-gavel"></i></a>
                <a href="javascript:;" data-bs-toggle="tooltip" data-bs-placement="top" data-bs-title="View Judgement" class="icon js-view-judgement d-none"><i class="fas fa-gavel"></i></a>
                <a data-bs-toggle="tooltip" style="display:none" data-bs-placement="top" data-bs-title="Tooltip on top" class="icon"><i class="fas fa-download"></i></a>
              </div>
              <div class="tabview d1">
                <ul class="nav nav-pills" id="pills-tab" role="tablist">
                  <li class="nav-item" role="presentation">
                    <button class="nav-link active" id="pills-home-tab" data-bs-toggle="pill" data-bs-target="#documenttype" type="button" role="tab" aria-controls="documenttype" aria-selected="true">Document Type</button>
                  </li>
                  <li class="nav-item" role="presentation">
                    <button class="nav-link" id="pills-profile-tab" data-bs-toggle="pill" data-bs-target="#metadata" type="button" role="tab" aria-controls="metadata" aria-selected="false">Metadata</button>
                  </li>
                </ul>
              </div>
            </div>
            <div class="tab-content mt-3" id="pills-tabContent">
              <div class="tab-pane fade show active" id="documenttype" role="tabpanel" aria-labelledby="documenttype-tab">

                <div id="fileSelectionContainer" class="c-form c-form-xs u-fieldRadius8 u-fieldShadow u-fieldBorderClr1 u-fieldHeight48 ">
                  
                </div>

              </div>
              <div class="tab-pane fade" id="metadata" role="tabpanel" aria-labelledby="metadata-tab">
                <div id="metadataContainer" class="c-listcontainer list3 rowview"> <!--witharrow class add if u can use arrow in label-->
                </div>
              </div>
            </div>
          </div>
          <div class="c-boxContainer__content--rightsection">
            ${renderDownloadFilePartial()}
            ${renderPDFPartial()}
            ${renderDocxPartial()}
            ${renderPptxPartial()}
            <div id="mediaContainer">
              ${renderMediaPartial()}
            </div>
            ${renderTextImagePartial()}
            ${renderExcelPartial()}
            ${renderExcelViewerPartial()}
          </div>
        </div>
      </div>
    </div>
  </div>
  ${renderViewJudgementModal()}
  ${renderPassJudgementModal()}
  ${renderShareCommentModal()}
</div>
<div id="printContainer"></div>`;
