export function renderShareCommentModal() {
    const template = `
    <div class="modal fade" id="shareCommentModal" data-bs-backdrop="static" data-bs-keyboard="false" tabindex="-1" aria-hidden="true">
        <div class="modal-dialog modal-dialog-centered modal-xl">
            <div class="modal-content">
                <div class="modal-body" id="share-comment-modal-body">

                    <div class="row">
                        <div class="col-12">
                            <div class="formsection">
                                <section class="formsection__section pb-0">
                                    <div class="headwrap withIcon lightblue">
                                        <div class="headwrap-text">Share Comment</div>
                                    </div>

                                    <div class="sharecommentdetail">
                                        <div class="sharecommentdetail__leftsection">
                                            <div class="content"><span>Doc:</span> <span id="documentName"></span></div>
                                            <div class="content"><span>Page:</span> <span id ="pageNumber"></span></div>
                                        </div>
                                        <div class="sharecommentdetail__rightsection" id="share-comment-text"></div>
                                    </div>

                                    <div class="shareformsection">
                                        <div class="c-form c-form-xs col2 u-fieldRadius8 u-fieldShadow u-fieldBorderClr1 u-fieldHeight48">
                                            <div class="form-grider cop-form design1 with80percent set-frequencybase">
                                                
                                                <div class="cop-form--container">
                                                    <div class="dropdowns-customized sumo fs14__regular adm-u-fieldHeight48">
                                                        <select multiple="multiple" id="user-select" placeholder="Search User" class="testSelAll">
                                                        </select>
                                                    </div>
                                                </div>

                                                <div class="cop-form--container set-frequencydropdown">
                                                    <div class="dropdowns-customized chosen fs14__regular u-fieldHeight38">
                                                        <select id="frequency-select" name="frequency" data-placeholder="Set Frequency" class="chzn-select" title="Set Frequency">
                                                            <option value="0">Permanent</option>
                                                            <option value="1">1 Week</option>
                                                            <option value="2">15 Days</option>
                                                            <option value="3">1 Month</option>
                                                        </select>
                                                    </div>
                                                </div>
                                            </div>

                                            <div class="form-grider cop-form design1 with120">
                                                <button class="u-button default radius-size6 size-full" id="add-share-user-btn">ADD</button>
                                            </div>
                                        </div>
                                    </div>

                                    <div class="userfrequencywrap">
                                        <h2 class="head">Users</h2>
                                        <div class="listwrap" id="shared-users-list">
                                            Comment is not shared with any user.
                                            <!-- Users will be dynamically added here -->
                                        </div>
                                    </div>

                                    <div class="d-flex justify-content-center">
                                        <button type="button" class="u-button greybg radius-size6 size-30 size-w117 mt-3"
                                            data-bs-dismiss="modal">
                                            <span>Cancel</span>
                                        </button>
                                        <button type="button" class="u-button default radius-size6 size-30 size-w117 mt-3 ml10"
                                            id="save-shared-comment-btn">
                                            <span>Save</span>
                                        </button>
                                    </div>
                                </section>
                            </div>
                        </div>
                    </div>
                
                </div>
            </div>
        </div>
    </div>
    `;
    return template;
}
